using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;public class ConsentServiceTests_SyncFromBlockchain_WithFakeId_ShouldReturnErrorMessage : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "ConsentService"    };    [SkippableFact]    public async Task SyncFromBlockchain_WithFakeId_ShouldReturnErrorMessage()    {    await AuthenticateAsAdminAsync(ConsentClient);    var response = await PostWithRetryAsync(ConsentClient, ApiEndpoints.Consents.SyncFromBlockchain("fake-consent-chain-id"), null);        var json = await ReadJsonResponseAsync(response);    Assert.False(string.IsNullOrEmpty(json.GetProperty("message").GetString()));    }}
